507	func dirtyWorktreePaths(dir string) []string {
508		out, err := internalgit.Command(context.Background(), dir, "status", "--porcelain", "--untracked-files=all").Output()
509		if err != nil {
510			return nil
511		}
512		var paths []string
513		seen := map[string]bool{}
514		for _, line := range strings.Split(string(out), "\n") {
515			line = strings.TrimRight(line, "\r")
516			if strings.TrimSpace(line) == "" || len(line) < 4 {
517				continue
518			}
519			path := strings.TrimSpace(line[3:])
520			if idx := strings.Index(path, " -> "); idx >= 0 {
521				path = strings.TrimSpace(path[idx+4:])
522			}
523			if path == "" || seen[path] {
524				continue
525			}
526			seen[path] = true
527			paths = append(paths, path)
528		}
529		return paths
530	}
