532	// EvidenceLandExcludePathspecs returns git pathspec-exclusion fragments
533	// applied when landEvidence / VerifyCleanWorktree stage the evidence
534	// directory. Only excludes the multi-thousand-line embedded session log
535	// (the single file that actually explodes past provider context
536	// limits). prompt.md, usage.json, manifest.json, and result.json remain
537	// tracked — they are small and serve the audit-trail contract. The
538	// gitignore written by `ddx init` already treats .ddx/executions/*/
539	// embedded as ignored; this pathspec is defence-in-depth for force-add
540	// paths.
541	//
542	// Regression anchor: ddx-39e27896 — session logs landed as tracked
543	// evidence caused retry prompts to balloon past 2M+ tokens and crash
544	// every provider with n_keep > n_ctx.
545	func EvidenceLandExcludePathspecs() []string {
546		return []string{
547			":(exclude,glob).ddx/executions/*/embedded/**",
548		}
549	}
550	
551	// EvidenceReviewExcludePathspecs returns git pathspec-exclusion fragments
552	// applied when review-prompt synthesis runs `git show <rev>` over the
553	// evidence commit. Broader than EvidenceLandExcludePathspecs: excludes
554	// prompt.md and usage.json too, because even though they're tracked for
555	// audit, they're execution-artifact noise from the reviewer's
556	// perspective — the reviewer wants to see the implementation diff, not
557	// the prior attempt's prompt or token counters. This also protects
558	// against old commits (pre-fix) that committed the session log
559	// directly.
560	//
561	// Regression anchor: ddx-39e27896.
562	func EvidenceReviewExcludePathspecs() []string {
563		return []string{
564			":(exclude,glob).ddx/executions/*/embedded/**",
565			":(exclude,glob).ddx/executions/*/prompt.md",
566			":(exclude,glob).ddx/executions/*/usage.json",
567		}
568	}
569	
570	// SynthesizeCommit stages real file changes, explicitly excluding harness noise
571	// paths, and creates a commit with msg as the commit message. Returns (true, nil)
572	// when a commit was made, (false, nil) when nothing real remained to commit
573	// after exclusions, and (false, err) on failure.
574	func (r *RealGitOps) SynthesizeCommit(dir, msg string) (bool, error) {
575		// Do NOT list already-gitignored paths (.ddx/agent-logs, .ddx/workers) as
576		// :(exclude) pathspecs. Git treats a path named by :(exclude) as explicitly
577		// referenced, so when the path is also .gitignored git emits "The following
578		// paths are ignored by one of your .gitignore files" AND exits 1 — even
579		// though the pathspec is trying to SKIP it. Paths already in .gitignore are
580		// excluded by default; excludes here are only for paths that would
581		// otherwise be tracked.
582		addArgs := []string{
583			"add", "-A", "--",
584			".",
585		}
586		addArgs = append(addArgs, synthesizeCommitExcludePathspecs(dir)...)
587		if err := internalgit.Command(context.Background(), dir, addArgs...).Run(); err != nil {
588			return false, fmt.Errorf("staging changes: %w", err)
589		}
590		statusOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
591		if len(bytes.TrimSpace(statusOut)) == 0 {
592			return false, nil
593		}
594		if msg == "" {
595			msg = "chore: execute-bead synthesized result commit"
596		}
597		out, err := internalgit.Command(context.Background(), dir, "commit", "-m", msg).CombinedOutput()
598		if err != nil {
599			return false, fmt.Errorf("synthesize commit: %s: %w", strings.TrimSpace(string(out)), err)
600		}
601		return true, nil
602	}
603	
604	// checkpointPreDispatchDirt captures DDx bookkeeping changes as a commit on
605	// the current branch without using the caller checkout's real index or commit
606	// hooks. The checkpoint is intentionally narrow: if the parent checkout also
607	// contains ordinary implementation files, the attempt fails with an actionable
608	// error so those changes can be committed in the bead's substantive
609	// [ddx-<id>] commit instead of being folded into the checkpoint.
610	const preDispatchCheckpointDirtyRefusalPrefix = "checkpoint refused to absorb implementation changes outside DDx bookkeeping: "
611	const preDispatchDirtyPreserveRefPrefix = "refs/ddx/pre-dispatch/"
612	
613	// PreDispatchDirtyPreservation records the recoverable handle DDx created when
614	// it preserved implementation dirt before a watch-mode redispatch.
615	type PreDispatchDirtyPreservation struct {
616		DirtyPaths     []string
617		PreserveRef    string
618		RecoverCommand string
619	}
620

 620	
 621	var preDispatchDirtyPathLister = func(projectRoot string) ([]string, error) {
 622		return preDispatchCheckpointDirtyPaths(projectRoot)
 623	}
 624	
 625	func normalizePreDispatchDirtyPaths(paths []string) []string {
 626		seen := make(map[string]bool, len(paths))
 627		normalized := make([]string, 0, len(paths))
 628		for _, path := range paths {
 629			path = filepath.ToSlash(strings.TrimSpace(path))
 630			if path == "" || seen[path] {
 631				continue
 632			}
 633			seen[path] = true
 634			normalized = append(normalized, path)
 635		}
 636		sort.Strings(normalized)
 637		return normalized
 638	}
 639	
 640	func intersectPreDispatchDirtyPaths(current, want []string) []string {
 641		if len(current) == 0 || len(want) == 0 {
 642			return nil
 643		}
 644		wantSet := make(map[string]bool, len(want))
 645		for _, path := range want {
 646			wantSet[path] = true
 647		}
 648		var overlap []string
 649		for _, path := range current {
 650			if wantSet[path] {
 651				overlap = append(overlap, path)
 652			}
 653		}
 654		sort.Strings(overlap)
 655		return overlap
 656	}
 657	
 658	func classifyPreDispatchDirtyPaths(dirtyPaths []string) (allowedPaths, blockedPaths []string) {
 659		for _, path := range normalizePreDispatchDirtyPaths(dirtyPaths) {
 660			if preDispatchCheckpointAllowedPath(path) {
 661				allowedPaths = append(allowedPaths, path)
 662				continue
 663			}
 664			blockedPaths = append(blockedPaths, path)
 665		}
 666		return allowedPaths, blockedPaths
 667	}
 668	
 669	// stablePreDispatchImplementationDirtyPaths re-reads the project dirt and only
 670	// treats implementation paths as actionable when they survive the immediate
 671	// recheck. This filters transient rename/delete paths that can briefly appear
 672	// in watch mode right after a successful land.
 673	func stablePreDispatchImplementationDirtyPaths(projectRoot string, dirtyPaths []string) ([]string, []string, error) {
 674		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
 675		if projectRoot == "" || len(normalized) == 0 {
 676			return normalized, normalized, nil
 677		}
 678	
 679		currentPaths, err := preDispatchDirtyPathLister(projectRoot)
 680		if err != nil {
 681			return nil, nil, fmt.Errorf("rechecking pre-dispatch dirt: %w", err)
 682		}
 683		return intersectPreDispatchDirtyPaths(currentPaths, normalized), currentPaths, nil
 684	}
 685	
 686	func resolveOptionalGitRef(dir, ref string) (string, bool) {
 687		out, err := internalgit.Command(context.Background(), dir, "rev-parse", "-q", "--verify", ref).Output()
 688		if err != nil {
 689			return "", false
 690		}
 691		sha := strings.TrimSpace(string(out))
 692		if sha == "" {
 693			return "", false
 694		}
 695		return sha, true
 696	}
 697	
 698	func preDispatchDirtyRecoverCommand(preserveRef string) string {
 699		if preserveRef == "" {
 700			return ""
 701		}
 702		return "git stash apply " + preserveRef
 703	}
 704	
 705	func preservePreDispatchDirtyPaths(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
 706		if projectRoot == "" {
 707			return nil, fmt.Errorf("project root is required for pre-dispatch dirty preservation")
 708		}
 709		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
 710		if len(normalized) == 0 {
 711			return nil, fmt.Errorf("no dirty implementation paths to preserve")
 712		}
 713	
 714		var preserved *PreDispatchDirtyPreservation
 715		if err := withTrackerLock(projectRoot, "preserve_dirt", func() error {
 716			var err error
 717			preserved, err = preservePreDispatchDirtyPathsLocked(projectRoot, normalized)
 718			return err
 719		}); err != nil {
 720			return nil, err
 721		}
 722		return preserved, nil
 723	}
 724	
 725	func preservePreDispatchDirtyPathsLocked(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
 726		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
 727			return nil, fmt.Errorf("verifying project worktree for pre-dispatch preservation: %w", err)
 728		}
 729		if out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput(); err != nil {
 730			return nil, fmt.Errorf("resolving HEAD for pre-dispatch preservation: %s: %w", strings.TrimSpace(string(out)), err)
 731		}
 732	
 733		stashBefore, _ := resolveOptionalGitRef(projectRoot, "refs/stash")
 734		preserveID := GenerateAttemptID()
 735		preserveRef := preDispatchDirtyPreserveRefPrefix + preserveID
 736		stashMsg := "ddx pre-dispatch preserve " + preserveID
 737		stashArgs := []string{"stash", "push", "--include-untracked", "--message", stashMsg, "--"}
 738		stashArgs = append(stashArgs, dirtyPaths...)
 739		if out, err := internalgit.Command(context.Background(), projectRoot, stashArgs...).CombinedOutput(); err != nil {
 740			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths: %s: %w", strings.TrimSpace(string(out)), err)
 741		}
 742	
 743		stashAfter, ok := resolveOptionalGitRef(projectRoot, "refs/stash")
 744		if !ok || stashAfter == "" || stashAfter == stashBefore {
 745			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths did not create a recoverable stash entry")
 746		}
 747		if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", preserveRef, stashAfter).CombinedOutput(); err != nil {
 748			return nil, fmt.Errorf("pinning pre-dispatch dirty preservation ref: %s: %w", strings.TrimSpace(string(out)), err)
 749		}
 750		_, _ = internalgit.Command(context.Background(), projectRoot, "stash", "drop", "stash@{0}").CombinedOutput()
 751	
 752		remainingPaths, err := preDispatchDirtyPathLister(projectRoot)
 753		if err != nil {
 754			return nil, fmt.Errorf("verifying preserved pre-dispatch dirt: %w", err)
 755		}
 756		if overlap := intersectPreDispatchDirtyPaths(remainingPaths, dirtyPaths); len(overlap) > 0 {
 757			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths left the project worktree dirty: %s", strings.Join(overlap, ", "))
 758		}
 759	
 760		return &PreDispatchDirtyPreservation{
 761			DirtyPaths:     append([]string(nil), dirtyPaths...),
 762			PreserveRef:    preserveRef,
 763			RecoverCommand: preDispatchDirtyRecoverCommand(preserveRef),
 764		}, nil
 765	}
 766	
 767	func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
 768		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
 769			return false, nil
 770		}
 771		headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").Output()
 772		if err != nil {
 773			return false, nil
 774		}
 775		head := strings.TrimSpace(string(headOut))
 776		if head == "" {
 777			return false, nil
 778		}
 779	
 780		skipWorktreePaths, err := checkpointSkipWorktreePaths(projectRoot)
 781		if err != nil {
 782			return false, err
 783		}
 784	
 785		dirtyPaths, err := preDispatchDirtyPathLister(projectRoot)
 786		if err != nil {
 787			return false, err
 788		}
 789		if len(dirtyPaths) == 0 {
 790			return false, nil
 791		}
 792	
 793		allowedPaths, blockedPaths := classifyPreDispatchDirtyPaths(dirtyPaths)
 794		if len(blockedPaths) > 0 {
 795			stableBlockedPaths, currentDirtyPaths, err := stablePreDispatchImplementationDirtyPaths(projectRoot, blockedPaths)
 796			if err != nil {
 797				return false, err
 798			}
 799			if len(stableBlockedPaths) > 0 {
 800				return false, fmt.Errorf(
 801					"%s%s; commit or clean those files before rerunning so the bead's [ddx-<id>] substantive commit stays intentional",
 802					preDispatchCheckpointDirtyRefusalPrefix,
 803					strings.Join(stableBlockedPaths, ", "),
 804				)
 805			}
 806			allowedPaths, _ = classifyPreDispatchDirtyPaths(currentDirtyPaths)
 807		}
 808		if len(allowedPaths) == 0 {
 809			return false, nil
 810		}
 811	
 812		indexFile, err := config.CreateExecutionScratch(projectRoot, "ddx-pre-dispatch-index-*")
 813		if err != nil {
 814			return false, fmt.Errorf("creating temp checkpoint index: %w", err)
 815		}
 816		indexPath := indexFile.Name()
 817		_ = indexFile.Close()
 818		_ = os.Remove(indexPath)
 819		defer func() { _ = os.Remove(indexPath) }()
 820	
 821		gitWithIndex := func(args ...string) ([]byte, error) {
 822			cmd := internalgit.Command(context.Background(), projectRoot, args...)
 823			cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
 824			return cmd.CombinedOutput()
 825		}
 826	
 827		if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
 828			return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
 829		}
 830	
 831		addArgs := []string{"add", "-A", "--force", "--"}
 832		addArgs = append(addArgs, allowedPaths...)
 833		if out, err := gitWithIndex(addArgs...); err != nil {
 834			return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
 835		}
 836	
 837		changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
 838		if err != nil {
 839			return false, fmt.Errorf("checking checkpoint diff: %w", err)
 840		}
 841		if len(bytes.TrimSpace(changedOut)) == 0 {
 842			return false, nil
 843		}
 844	
 845		treeOut, err := gitWithIndex("write-tree")
 846		if err != nil {
 847			return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
 848		}
 849		tree := strings.TrimSpace(string(treeOut))
 850		msg := "chore: checkpoint pre-execute-bead " + attemptID
 851		commitOut, err := internalgit.Command(context.Background(), projectRoot,
 852			"-c", "user.name=ddx-checkpoint",
 853			"-c", "user.email=checkpoint@ddx.local",
 854			"commit-tree", tree, "-p", head, "-m", msg,
 855		).CombinedOutput()
 856		if err != nil {
 857			return false, fmt.Errorf("creating checkpoint commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
 858		}
 859		commit := strings.TrimSpace(string(commitOut))
 860	
 861		refOut, _ := internalgit.Command(context.Background(), projectRoot, "symbolic-ref", "-q", "HEAD").Output()
 862		ref := strings.TrimSpace(string(refOut))
 863		if ref == "" {
 864			ref = "HEAD"
 865		}
 866		if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", ref, commit, head).CombinedOutput(); err != nil {
 867			return false, fmt.Errorf("advancing checkpoint ref: %s: %w", strings.TrimSpace(string(out)), err)
 868		}
 869		if out, err := internalgit.Command(context.Background(), projectRoot, "read-tree", "HEAD").CombinedOutput(); err != nil {
 870			return false, fmt.Errorf("syncing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
 871		}
 872		if err := restoreCheckpointSkipWorktreePaths(projectRoot, skipWorktreePaths); err != nil {
 873			return false, err
 874		}
 875		return true, nil
 876	}
 877	
 878	func checkpointSkipWorktreePaths(projectRoot string) ([]string, error) {
 879		out, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "-t", "-z").Output()
 880		if err != nil {
 881			return nil, fmt.Errorf("listing skip-worktree paths: %w", err)
 882		}
 883		var paths []string
 884		for len(out) > 0 {
 885			recordEnd := bytes.IndexByte(out, 0)
 886			if recordEnd == -1 {
 887				recordEnd = len(out)
 888			}
 889			record := out[:recordEnd]
 890			if recordEnd < len(out) {
 891				out = out[recordEnd+1:]
 892			} else {
 893				out = nil
 894			}
 895			if len(record) < 3 || record[0] != 'S' || record[1] != ' ' {
 896				continue
 897			}
 898			path := filepath.ToSlash(string(record[2:]))
 899			if path != "" {
 900				paths = append(paths, path)
 901			}
 902		}
 903		return paths, nil
 904	}
 905	
 906	func restoreCheckpointSkipWorktreePaths(projectRoot string, paths []string) error {
 907		for start := 0; start < len(paths); start += 100 {
 908			end := start + 100
 909			if end > len(paths) {
 910				end = len(paths)
 911			}
 912			args := append([]string{"update-index", "--skip-worktree", "--"}, paths[start:end]...)
 913			if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
 914				return fmt.Errorf("restoring skip-worktree paths after checkpoint index sync: %s: %w", strings.TrimSpace(string(out)), err)
 915			}
 916		}
 917		return nil
 918	}
 919	
 920	// isMaterializedSkillSymlink reports whether a path is a skill directory symlink
 921	// that has been materialized into a real directory by an external tool. Skill
 922	// symlinks (.crush/skills/*, .claude/skills/*, .agents/skills/*) tracked in git
 923	// as symlinks (mode 120000) but present in the working tree as directories are
 924	// benign and do not indicate uncommitted implementation changes.
 925	func isMaterializedSkillSymlink(projectRoot, path string) bool {
 926		// Check if path is in a skill directory root
 927		skillDirs := []string{".crush/skills", ".claude/skills", ".agents/skills"}
 928		var isSkillPath bool
 929		for _, skillDir := range skillDirs {
 930			if path == skillDir || strings.HasPrefix(path, skillDir+"/") {
 931				isSkillPath = true
 932				break
 933			}
 934		}
 935		if !isSkillPath {
 936			return false
 937		}
 938	
 939		// Check if it's tracked in git as a symlink
 940		mode, err := internalgit.Command(context.Background(), projectRoot,
 941			"ls-files", "--stage", "--", path).Output()
 942		if err != nil || len(mode) == 0 {
 943			return false
 944		}
 945		// ls-files --stage output is: "<mode> <object> <stage>\t<file>"
 946		// We need to extract the mode field (first field, 120000 for symlink)
 947		parts := strings.Fields(string(mode))
 948		if len(parts) < 1 {
 949			return false
 950		}
 951		gitMode := parts[0]
 952		if gitMode != "120000" {
 953			return false
 954		}
 955	
 956		// Check if the working tree has it as a directory
 957		fullPath := filepath.Join(projectRoot, filepath.FromSlash(path))
 958		info, err := os.Stat(fullPath)
 959		if err != nil {
 960			return false
 961		}
 962		return info.IsDir()
 963	}
 964	
 965	func preDispatchCheckpointDirtyPaths(projectRoot string) ([]string, error) {
 966		out, err := internalgit.Command(context.Background(), projectRoot,
 967			"status", "--porcelain=v1", "-z", "--untracked-files=all", "--ignored=matching", "--", ".").Output()
 968		if err != nil {
 969			return nil, fmt.Errorf("listing checkpoint dirt: %w", err)
 970		}
 971		if len(out) == 0 {
 972			return nil, nil
 973		}
 974	
 975		seen := make(map[string]bool)
 976		paths := make([]string, 0, 8)
 977		for len(out) > 0 {
 978			recordEnd := bytes.IndexByte(out, 0)
 979			if recordEnd == -1 {
 980				recordEnd = len(out)
 981			}
 982			record := out[:recordEnd]
 983			if recordEnd < len(out) {
 984				out = out[recordEnd+1:]
 985			} else {
 986				out = nil
 987			}
 988			if len(record) < 3 {
 989				continue
 990			}
 991			status := string(record[:2])
 992			path := filepath.ToSlash(string(record[3:]))
 993			if status == "!!" && !preDispatchCheckpointAllowedPath(path) {
 994				continue
 995			}
 996			if preDispatchCheckpointIgnoredPath(path) {
 997				continue
 998			}
 999			if isMaterializedSkillSymlink(projectRoot, path) {
1000				continue
1001			}
1002			if path != "" && !seen[path] {
1003				seen[path] = true
1004				paths = append(paths, path)
1005			}
1006			if record[0] == 'R' || record[0] == 'C' {
1007				recordEnd = bytes.IndexByte(out, 0)
1008				if recordEnd == -1 {
1009					recordEnd = len(out)
1010				}
1011				record = out[:recordEnd]
1012				if recordEnd < len(out) {
1013					out = out[recordEnd+1:]
1014				} else {
1015					out = nil
1016				}
1017				path := filepath.ToSlash(string(record))
1018				if status == "!!" && !preDispatchCheckpointAllowedPath(path) {
1019					continue
1020				}
1021				if preDispatchCheckpointIgnoredPath(path) {
